"use strict";(self.webpackChunkdocs=self.webpackChunkdocs||[]).push([[465],{5454:e=>{e.exports=JSON.parse('{"blogPosts":[{"id":"3.0.0","metadata":{"permalink":"/release-notes/3.0.0","editUrl":"https://github.com/swipload/docs/tree/main/release-notes/2023-11-05-3.0.0.mdx","source":"@site/release-notes/2023-11-05-3.0.0.mdx","title":"3.0.0: Shipment 1.0","description":"Features","date":"2023-11-05T00:00:00.000Z","formattedDate":"November 5, 2023","tags":[{"label":"shipper","permalink":"/release-notes/tags/shipper"},{"label":"carrier","permalink":"/release-notes/tags/carrier"},{"label":"shipment","permalink":"/release-notes/tags/shipment"},{"label":"driver","permalink":"/release-notes/tags/driver"}],"hasTruncateMarker":true,"authors":[],"frontMatter":{"slug":"3.0.0","title":"3.0.0: Shipment 1.0","tags":["shipper","carrier","shipment","driver"]},"unlisted":false,"nextItem":{"title":"Hotfix 2.51.2: Settlements","permalink":"/release-notes/2.51.2"}},"content":"import Tabs from \'@theme/Tabs\';\\nimport TabItem from \'@theme/TabItem\';\\n\\n## Features\\n\\n### Shipments\\n\\nCreate, communicate, negotiate and get one price for multiple freight orders using a single Shipment. Order a FTL or LTL by combining multiple freight orders. A shipment can have a single or multiple pickup points and a single or multiple delivery points, and enables individual PODs for different end customers on a single shipment.\\n\\nShipments support the same features as regular freight orders, like:\\n\\n- Request quote from one or many carriers\\n- Send to carrier as fixed price shipment\\n- Send to carrier as time & material pricing\\n- Communicate with carriers and drivers on a shipment\\n- Share to spot market for instant resolving of your shipment need\\n- Agreements, with multiple terms for your current carrier(s)\\n- Integrations with ERPs and TMSs\\n\\nand much much more.\\n\\n### Photo documentation\\n\\nWhen signing for pickup and/or delivery you may now attach one or more photos documenting the pickup or delivery. Photos are visible for the shipper and can be presented to the end customer.\\n\\n### Deviation handling\\n\\nIf a deviation occurs during the delivery process, you may now report it immediately, i.e. when signing for pickup or delivery. Attach photos to deviations for adding additional context and documentation.\\n\\n\x3c!--truncate--\x3e\\n\\n## Bug fixes\\n\\nNone\\n\\n## RSS Feed\\n\\nSubscribe to all our release notes via RSS. The feeds can be found at:\\n\\n<Tabs>\\n<TabItem value=\\"RSS\\">\\n\\n```text\\nhttps://docs.swipload.com/release-notes/rss.xml\\n```\\n\\n</TabItem>\\n<TabItem value=\\"Atom\\">\\n\\n```text\\nhttps://docs.swipload.com/release-notes/atom.xml\\n```\\n\\n</TabItem>\\n<TabItem value=\\"JSON\\">\\n\\n```text\\nhttps://docs.swipload.com/release-notes/feed.json\\n```\\n\\n</TabItem>\\n</Tabs>"},{"id":"2.51.2","metadata":{"permalink":"/release-notes/2.51.2","editUrl":"https://github.com/swipload/docs/tree/main/release-notes/2023-09-21-2.51.2.mdx","source":"@site/release-notes/2023-09-21-2.51.2.mdx","title":"Hotfix 2.51.2: Settlements","description":"Bug fixes","date":"2023-09-21T00:00:00.000Z","formattedDate":"September 21, 2023","tags":[{"label":"carrier","permalink":"/release-notes/tags/carrier"},{"label":"driver","permalink":"/release-notes/tags/driver"}],"hasTruncateMarker":true,"authors":[],"frontMatter":{"slug":"2.51.2","title":"Hotfix 2.51.2: Settlements","tags":["carrier","driver"]},"unlisted":false,"prevItem":{"title":"3.0.0: Shipment 1.0","permalink":"/release-notes/3.0.0"},"nextItem":{"title":"2.51: Multi-language support","permalink":"/release-notes/2.51"}},"content":"import Tabs from \'@theme/Tabs\';\\nimport TabItem from \'@theme/TabItem\';\\n\\n## Bug fixes\\n\\n- #2687 Issue creating final settlement for delivered freight order\\n- #2689 Issue for driver to add comment when signing for delivered\\n\\n\x3c!--truncate--\x3e\\n\\n## RSS Feed\\n\\nSubscribe to all our release notes via RSS. The feeds can be found at:\\n\\n<Tabs>\\n<TabItem value=\\"RSS\\">\\n\\n```text\\nhttps://docs.swipload.com/release-notes/rss.xml\\n```\\n\\n</TabItem>\\n<TabItem value=\\"Atom\\">\\n\\n```text\\nhttps://docs.swipload.com/release-notes/atom.xml\\n```\\n\\n</TabItem>\\n<TabItem value=\\"JSON\\">\\n\\n```text\\nhttps://docs.swipload.com/release-notes/feed.json\\n```\\n\\n</TabItem>\\n</Tabs>"},{"id":"2.51","metadata":{"permalink":"/release-notes/2.51","editUrl":"https://github.com/swipload/docs/tree/main/release-notes/2023-09-19-2.51.mdx","source":"@site/release-notes/2023-09-19-2.51.mdx","title":"2.51: Multi-language support","description":"This release focuses on multiple language support, handling localisation in UI, PODs, notifications, SMS\'es and emails in regards to users or receivers language. To update your language setting go to your profile settings.","date":"2023-09-19T00:00:00.000Z","formattedDate":"September 19, 2023","tags":[{"label":"carrier","permalink":"/release-notes/tags/carrier"},{"label":"i18n","permalink":"/release-notes/tags/i-18-n"},{"label":"shipper","permalink":"/release-notes/tags/shipper"}],"hasTruncateMarker":false,"authors":[],"frontMatter":{"slug":"2.51","title":"2.51: Multi-language support","tags":["carrier","i18n","shipper"]},"unlisted":false,"prevItem":{"title":"Hotfix 2.51.2: Settlements","permalink":"/release-notes/2.51.2"}},"content":"import Tabs from \'@theme/Tabs\';\\nimport TabItem from \'@theme/TabItem\';\\n\\nThis release focuses on multiple language support, handling localisation in UI, PODs, notifications, SMS\'es and emails in regards to users or receivers language. To update your language setting go to your [profile settings](https://app.swipload.no/settings/your-profile).\\n\\n## Features\\n\\n### Language support\\n\\n- #2409 As a User I can choose English or Norwegian language in my profile settings, to change the literal language in the application\\n- #2630 As a User my application is correctly rendered with the language tied to my user profile\\n- #2625 As an Administrator and Invitee I can assign default language when [creating a User](https://app.swipload.no/settings/swipload-users)\\n\\n### Freights\\n\\n- #1713 As a Shipper I can see \\"Sent to\\" and \\"Opened by\\" also for my colleagues\' shipments\\n\\n## Bug fixes\\n\\n- #2353 Lost details on the waybill (consignment note) for settlement freights\\n- #2052 Carrier details does not appear in the consignment note on for settlement or fixed price (freight requests) freight orders\\n- #2626 \'Send freight order\' button in freight-card modal is inactive, and can not be clicked\\n- #2627 On \'send-to-carrier\' page, the carrier cards are misaligned\\n- #2668 Cannot make Settlement report in for certain companies\\n\\n## RSS Feed\\n\\nSubscribe to all our release notes via RSS. The feeds can be found at:\\n\\n<Tabs>\\n<TabItem value=\\"RSS\\">\\n\\n```text\\nhttps://docs.swipload.com/release-notes/rss.xml\\n```\\n\\n</TabItem>\\n<TabItem value=\\"Atom\\">\\n\\n```text\\nhttps://docs.swipload.com/release-notes/atom.xml\\n```\\n\\n</TabItem>\\n<TabItem value=\\"JSON\\">\\n\\n```text\\nhttps://docs.swipload.com/release-notes/feed.json\\n```\\n\\n</TabItem>\\n</Tabs>"}]}')}}]);